function intPow(base, exp) {
  let result = 1;
  for (let i = 0; i < exp; i++) result *= base;
  return result;
}

tests:
if (intPow(2, 10) !== 1024) throw new Error('2^10');
if (intPow(5, 0) !== 1) throw new Error('5^0');
if (intPow(3, 3) !== 27) throw new Error('3^3');
if (intPow(7, 1) !== 7) throw new Error('7^1');

